import { execFileSync } from "node:child_process";
import crypto from "node:crypto";
import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { resolveAgentSessionKey } from "./agentSessionKey.js";
import { getAgentSessionId } from "./getAgentSessionId.js";
const SESSIONS_DIR = path.join(os.homedir(), ".config", "bitfab", "sessions");
function shortHash(input) {
    return crypto.createHash("sha256").update(input).digest("hex").slice(0, 16);
}
function sessionFilePathForKey(key) {
    return path.join(SESSIONS_DIR, `${shortHash(key)}.json`);
}
function sessionFilePath() {
    return sessionFilePathForKey(resolveAgentSessionKey());
}
function writeStateFile(target, state) {
    fs.mkdirSync(path.dirname(target), { recursive: true });
    const tmp = `${target}.${process.pid}.tmp`;
    fs.writeFileSync(tmp, `${JSON.stringify(state, null, 2)}\n`);
    fs.renameSync(tmp, target);
}
function readStateFile(filePath) {
    try {
        const raw = fs.readFileSync(filePath, "utf-8");
        const parsed = JSON.parse(raw);
        if (typeof parsed.sessionId !== "string" ||
            typeof parsed.serviceUrl !== "string") {
            return null;
        }
        return parsed;
    }
    catch {
        return null;
    }
}
// --- Legacy support ---
function legacySessionScope() {
    return shortHash(getAgentSessionId() ?? process.cwd());
}
function legacyFilePath() {
    return path.join(os.homedir(), ".config", "bitfab", `active-studio-session.${legacySessionScope()}.json`);
}
function readLegacySession() {
    try {
        const raw = fs.readFileSync(legacyFilePath(), "utf-8");
        const parsed = JSON.parse(raw);
        if (parsed.closedAt != null || parsed.endedAt != null) {
            return null;
        }
        if (typeof parsed.sessionId !== "string" ||
            typeof parsed.serviceUrl !== "string" ||
            typeof parsed.pid !== "number" ||
            typeof parsed.startedAt !== "string") {
            return null;
        }
        const legacy = parsed;
        return {
            sessionId: legacy.sessionId,
            serviceUrl: legacy.serviceUrl,
            windowPid: legacy.windowPid ?? null,
            pollerPid: legacy.pid,
            source: "direct",
            openedAt: legacy.startedAt,
            currentPath: null,
            authenticated: true,
            windowState: "open",
            agentIntent: "open",
            lastBrowserPingAt: null,
            browserConnected: false,
            lastEventAt: null,
            lastEventCursor: null,
            agentSessionKey: null,
            worktreeRoot: null,
        };
    }
    catch {
        return null;
    }
}
// --- Public API (implicit key from current agent) ---
export function writeActiveStudioSession(init) {
    const state = {
        sessionId: init.sessionId,
        serviceUrl: init.serviceUrl,
        windowPid: init.windowPid ?? null,
        pollerPid: process.pid,
        source: init.source ?? "direct",
        openedAt: new Date().toISOString(),
        currentPath: init.currentPath ?? null,
        authenticated: init.authenticated ?? true,
        windowState: "open",
        agentIntent: "open",
        lastBrowserPingAt: null,
        browserConnected: false,
        lastEventAt: null,
        lastEventCursor: null,
        agentSessionKey: null,
        worktreeRoot: null,
    };
    writeStateFile(sessionFilePath(), state);
}
export function readActiveStudioSession() {
    return readStateFile(sessionFilePath()) ?? readLegacySession();
}
export function updateActiveStudioSession(updates) {
    const current = readStateFile(sessionFilePath());
    if (!current) {
        return null;
    }
    const updated = { ...current, ...updates };
    writeStateFile(sessionFilePath(), updated);
    return updated;
}
export function clearActiveStudioSession(sessionId, opts = {}) {
    try {
        const current = readStateFile(sessionFilePath());
        if (!current) {
            // Try clearing legacy file
            return clearLegacySession(sessionId, opts);
        }
        if (current.sessionId !== sessionId) {
            return false;
        }
        if (!opts.force &&
            current.pollerPid != null &&
            current.pollerPid !== process.pid &&
            isProcessAlive(current.pollerPid)) {
            return false;
        }
        fs.unlinkSync(sessionFilePath());
        return true;
    }
    catch {
        return false;
    }
}
function clearLegacySession(sessionId, opts = {}) {
    try {
        const raw = fs.readFileSync(legacyFilePath(), "utf-8");
        const parsed = JSON.parse(raw);
        if (parsed.sessionId !== sessionId) {
            return false;
        }
        if (!opts.force &&
            typeof parsed.pid === "number" &&
            parsed.pid !== process.pid &&
            isProcessAlive(parsed.pid)) {
            return false;
        }
        fs.unlinkSync(legacyFilePath());
        return true;
    }
    catch {
        return false;
    }
}
// --- Keyed API (for daemon use) ---
export function writeSessionStateForKey(key, state) {
    writeStateFile(sessionFilePathForKey(key), state);
}
export function readSessionStateForKey(key) {
    return readStateFile(sessionFilePathForKey(key));
}
export function updateSessionStateForKey(key, updates) {
    const target = sessionFilePathForKey(key);
    const current = readStateFile(target);
    if (!current) {
        return null;
    }
    const updated = { ...current, ...updates };
    writeStateFile(target, updated);
    return updated;
}
export function clearSessionStateForKey(key, sessionId) {
    try {
        const current = readStateFile(sessionFilePathForKey(key));
        if (!current || current.sessionId !== sessionId) {
            return false;
        }
        fs.unlinkSync(sessionFilePathForKey(key));
        return true;
    }
    catch {
        return false;
    }
}
export function readAllDaemonSessionStates() {
    try {
        const files = fs.readdirSync(SESSIONS_DIR);
        const states = [];
        for (const file of files) {
            if (!file.endsWith(".json")) {
                continue;
            }
            const state = readStateFile(path.join(SESSIONS_DIR, file));
            if (state &&
                state.source === "daemon" &&
                state.windowState !== "closed" &&
                state.agentSessionKey) {
                states.push(state);
            }
        }
        return states;
    }
    catch {
        return [];
    }
}
// --- Process utilities ---
function isProcessAlive(pid) {
    try {
        process.kill(pid, 0);
        return true;
    }
    catch (err) {
        return err.code === "EPERM";
    }
}
export function processStartToken(pid) {
    try {
        const out = execFileSync("ps", ["-o", "lstart=", "-p", String(pid)], {
            encoding: "utf-8",
            stdio: ["ignore", "pipe", "ignore"],
            timeout: 2000,
        }).trim();
        return out || null;
    }
    catch {
        return null;
    }
}
// --- Monitor lock (direct path only) ---
function monitorLockPath() {
    return path.join(SESSIONS_DIR, `${shortHash(resolveAgentSessionKey())}.monitor.lock`);
}
function monitorLockBody(pid) {
    return `${pid}\n${processStartToken(pid) ?? ""}`;
}
function isMonitorOwnerLive(owner) {
    if (!isProcessAlive(owner.pid)) {
        return false;
    }
    if (!owner.start) {
        return true;
    }
    const current = processStartToken(owner.pid);
    if (current === null) {
        return true;
    }
    return current === owner.start;
}
function readLockOwner(lock) {
    try {
        const [pidLine = "", ...rest] = fs.readFileSync(lock, "utf-8").split("\n");
        const pid = Number.parseInt(pidLine.trim(), 10);
        if (!Number.isInteger(pid)) {
            return null;
        }
        return { pid, start: rest.join("\n").trim() };
    }
    catch {
        return null;
    }
}
function stampMonitorPid() {
    const current = readStateFile(sessionFilePath());
    if (current) {
        writeStateFile(sessionFilePath(), { ...current, pollerPid: process.pid });
    }
}
export function tryClaimStudioMonitor() {
    const lock = monitorLockPath();
    fs.mkdirSync(path.dirname(lock), { recursive: true });
    for (let attempt = 0; attempt < 10; attempt++) {
        try {
            const fd = fs.openSync(lock, "wx");
            fs.writeSync(fd, monitorLockBody(process.pid));
            fs.closeSync(fd);
            stampMonitorPid();
            return true;
        }
        catch (err) {
            if (err.code !== "EEXIST") {
                throw err;
            }
            const owner = readLockOwner(lock);
            if (owner?.pid === process.pid) {
                return true;
            }
            if (owner && isMonitorOwnerLive(owner)) {
                return false;
            }
            try {
                fs.unlinkSync(lock);
            }
            catch { }
        }
    }
    stampMonitorPid();
    return true;
}
export function claimStudioMonitor() {
    try {
        const lock = monitorLockPath();
        fs.mkdirSync(path.dirname(lock), { recursive: true });
        fs.writeFileSync(lock, monitorLockBody(process.pid));
    }
    catch { }
    stampMonitorPid();
}
export function releaseStudioMonitor() {
    try {
        const lock = monitorLockPath();
        if (readLockOwner(lock)?.pid === process.pid) {
            fs.unlinkSync(lock);
        }
    }
    catch { }
}
